class MapScreen extends StatefulWidget { ... }
class _MapScreenState extends State<MapScreen> {
  late GoogleMapController mapController;
  LatLng? currentPosition;
  Set<Marker> markers = {};

  @override
  void initState() { super.initState(); _getUserLocation(); }

  Future<void> _getUserLocation() async { Position pos = await Geolocator.getCurrentPosition(); setState(() { currentPosition = LatLng(pos.latitude, pos.longitude); markers.add(Marker(markerId: MarkerId('current'), position: currentPosition!)); }); }

  @override
  Widget build(BuildContext context) { return Scaffold(body: currentPosition == null ? Center(child: CircularProgressIndicator()) : GoogleMap(initialCameraPosition: CameraPosition(target: currentPosition!, zoom: 15), markers: markers, onMapCreated: (controller) => mapController = controller)); } }
